# ---------- Standalone queue groups ----------

# Durable queue group used by dd-remote-queue-consumer replicas for critical runtime event logging and future alert fan-out.
# Service: shared
CRITICAL_EVENTS_LOGGER_QUEUE_GROUP = "dd-runtime-critical-events"

# Shared queue group used by lambda-runner replicas.
# Service: dd-gleam-lambda-runner
LAMBDA_RUNNER_QUEUE_GROUP = "dd-gleam-lambda-runner"

# Shared queue group used by slave solver pods so each branch-and-bound subproblem is solved once.
# Service: dd-ai-ml-pipeline
MIP_SOLVER_WORKERS_QUEUE_GROUP = "dd-in-house-mip-solver-node-workers"

# Shared queue group used by dd-remote-queue-consumer replicas so each task is only prepared once.
# Service: dd-remote-rest-api
THREAD_PREPARER_QUEUE_GROUP = "dd-remote-thread-preparer"

